import React, { useEffect, useState } from "react";
import { io } from "socket.io-client";
import "./chatBot.css";

const socket = io("http://localhost:3002");

const ChatBot = () => {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [isOpen, setIsOpen] = useState(false);

  // ==============================
  // Listen for AI Messages
  // ==============================
  useEffect(() => {
    const handleAIMessage = (msg) => {
      setMessages((prev) => [...prev, { type: "ai", text: msg }]);
    };

    socket.on("aiMessage", handleAIMessage);

    return () => {
      socket.off("aiMessage", handleAIMessage);
    };
  }, []);

  // ==============================
  // Send Message
  // ==============================
  const sendMessage = () => {
    if (!input.trim()) return;

    socket.emit("userMessage", input);

    setMessages((prev) => [...prev, { type: "user", text: input }]);
    setInput("");
  };

  return (
    <>
      {/* 🔥 Floating Image Icon (from public folder) */}
      <img
        src="/waveAgent.png"
        alt="Wave Agent"
        className="chat-icon-img"
        onClick={() => setIsOpen((prev) => !prev)}
      />

      {/* 🔥 Chat Window */}
      {isOpen && (
        <div className="chat-window">
          <div className="chat-header">
            Wave Agent
            <span
              className="close-btn"
              onClick={() => setIsOpen(false)}
            >
              ✖
            </span>
          </div>

          <div className="chat-body">
            {messages.map((msg, index) => (
              <div key={index} className={`msg ${msg.type}`}>
                {msg.text}
              </div>
            ))}
          </div>

          <div className="chat-input">
            <input
              type="text"
              value={input}
              placeholder="Ask about portfolio or buy stock..."
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && sendMessage()}
            />
            <button onClick={sendMessage}>Send</button>
          </div>
        </div>
      )}
    </>
  );
};

export default ChatBot;
